### Step 4.3 — Wire auth into WebSocket

**File**: `src/hooks/useLiveEvents.ts`

```typescript
export function useLiveEvents() {
  const token = useAppStore(state => state.auth.token);
  const connection = useWebSocketConnection({ authToken: token });
  // ...
