            </div>
            <div className="rounded-full bg-white/80 px-4 py-2 text-sm text-stone-600">
              {job.status}
            </div>
          </div>
          <div className="rounded-3xl bg-white/60 p-5">
            <p className="whitespace-pre-wrap leading-8 text-stone-800">{job.source_text}</p>
          </div>
