import { create } from "zustand";

import type { Voice } from "../types/api";
import type {
  AdminState,
  JobDetail,
  JobSummary,
  WsEnvelope,
} from "../types/events";

interface AppStore {
  jobs: Record<string, JobSummary>;
  voices: Voice[];
  adminState: AdminState | null;
  websocketStatus: "connecting" | "open" | "reconnecting" | "closed" | "error";
  lastSocketMessageAt: number | null;
  lastSocketError: string | null;
  reconnectAttempt: number;
  isSocketStale: boolean;
  lastEvent: WsEnvelope | null;
  setJobs: (jobs: Record<string, JobSummary>) => void;
  setVoices: (voices: Voice[]) => void;
  setAdminState: (adminState: AdminState) => void;
  setSocketState: (state: {
    status?: AppStore["websocketStatus"];
    lastMessageAt?: number | null;
    error?: string | null;
    reconnectAttempt?: number;
    isStale?: boolean;
  }) => void;
  applyEvent: (event: WsEnvelope) => void;
}

function upsertJob(
  jobs: Record<string, JobSummary>,
  nextJob: JobDetail,
): Record<string, JobSummary> {
  return { ...jobs, [nextJob.id]: toSummary(nextJob) };
}

function toSummary(job: JobDetail): JobSummary {
  return {
    id: job.id,
    title: job.title,
    status: job.status,
    voice_id: job.voice_id,
    model_id: job.model_id,
    is_active_listening: job.is_active_listening,
    total_chunks_emitted: job.total_chunks_emitted,
    total_chunks_completed: job.total_chunks_completed,
    buffered_seconds: job.buffered_seconds,
    completed_seconds: job.completed_seconds,
  };
}

export const useAppStore = create<AppStore>((set) => ({
  jobs: {},
  voices: [],
  adminState: null,
  websocketStatus: "connecting",
  lastSocketMessageAt: null,
  lastSocketError: null,
  reconnectAttempt: 0,
  isSocketStale: false,
  lastEvent: null,
  setJobs: (jobs) => set({ jobs }),
  setVoices: (voices) => set({ voices }),
  setAdminState: (adminState) => set({ adminState }),
  setSocketState: ({ status, lastMessageAt, error, reconnectAttempt, isStale }) =>
    set((state) => {
      if (
        (status !== undefined && status === state.websocketStatus) ||
        (lastMessageAt !== undefined && lastMessageAt === state.lastSocketMessageAt) ||
        (error !== undefined && error === state.lastSocketError) ||
        (reconnectAttempt !== undefined && reconnectAttempt === state.reconnectAttempt) ||
        (isStale !== undefined && isStale === state.isSocketStale)
      ) {
        return null;
      }

      return {
        ...state,
        websocketStatus: status ?? state.websocketStatus,
        lastSocketMessageAt: lastMessageAt ?? state.lastSocketMessageAt,
        lastSocketError: error ?? state.lastSocketError,
        reconnectAttempt: reconnectAttempt ?? state.reconnectAttempt,
        isSocketStale: isStale ?? state.isSocketStale,
      };
    }),
  applyEvent: (event) =>
    set((state) => {
      if (
        event.type === "job_created" ||
        event.type === "job_updated" ||
        event.type === "job_completed" ||
        event.type === "chunk_ready"
      ) {
        return {
          jobs: upsertJob(state.jobs, event.payload.job),
          lastEvent: event,
        };
      }

      if (event.type === "telemetry") {
        if (!state.adminState) {
          return { lastEvent: event };
        }
        return {
          adminState: {
            ...state.adminState,
            telemetry: event.payload.telemetry,
          },
          lastEvent: event,
        };
      }

      if (event.type === "admin_config_updated") {
        if (!state.adminState) {
          return { lastEvent: event };
        }
        return {
          adminState: {
            ...state.adminState,
            config: event.payload,
          },
          lastEvent: event,
        };
      }

      if (event.type === "scheduler_state") {
        if (!state.adminState) {
          return { lastEvent: event };
        }
        return {
          adminState: {
            ...state.adminState,
            scheduler: event.payload,
          },
          lastEvent: event,
        };
      }

      if (event.type === "model_state") {
        if (!state.adminState) {
          return { lastEvent: event };
        }
        const telemetry = state.adminState.telemetry;
        return {
          adminState: {
            ...state.adminState,
            telemetry: {
              queue_depth: telemetry.queue_depth,
              model_state: event.payload.state,
              idle_deadline: telemetry.idle_deadline,
              oom_count: telemetry.oom_count,
              recent_batches: telemetry.recent_batches,
              recent_events: telemetry.recent_events,
            },
          },
          lastEvent: event,
        };
      }

      return { lastEvent: event };
    }),
}));

