import { act, cleanup, render, screen, waitFor } from "@testing-library/react";

import { App } from "./App";
import { liveClient } from "../lib/live-client";
import { useAppStore } from "../state/store";

class MockWebSocket extends EventTarget {
  static CONNECTING = 0;
  static OPEN = 1;
  static CLOSING = 2;
  static CLOSED = 3;
  static instances: MockWebSocket[] = [];
  static latest: MockWebSocket | null = null;

  readyState = MockWebSocket.CONNECTING;

  constructor() {
    super();
    MockWebSocket.instances.push(this);
    MockWebSocket.latest = this;
    queueMicrotask(() => {
      this.readyState = MockWebSocket.OPEN;
      this.dispatchEvent(new Event("open"));
    });
  }

  close() {
    this.readyState = MockWebSocket.CLOSED;
    this.dispatchEvent(new Event("close"));
  }

  send(payload: string) {
    if (payload === "ping") {
      queueMicrotask(() => this.emit({ type: "pong", payload: {} }));
    }
  }

  emit(payload: object) {
    this.dispatchEvent(new MessageEvent("message", { data: JSON.stringify(payload) }));
  }

  fail() {
    this.dispatchEvent(new Event("error"));
    this.close();
  }
}

function seedStore() {
  useAppStore.setState({
    jobs: {},
    voices: [],
    adminState: {
      config: {
        idle_unload_seconds: 300,
        max_prebuffer_seconds: 300,
        target_buffer_seconds: 45,
        batch_candidates_small_model: [8, 7, 6, 5],
        batch_candidates_large_model: [6, 5, 4, 3],
        vram_soft_limit_mb: 9000,
        vram_hard_limit_mb: 11000,
      },
      scheduler: {
        queue_depth: 0,
        batch_candidates: [8, 7, 6, 5],
      },
      telemetry: {
        queue_depth: 0,
        model_state: "unloaded",
        idle_deadline: null,
        oom_count: 0,
        recent_batches: [],
        recent_events: [],
      },
    },
    websocketStatus: "connecting",
    lastSocketMessageAt: null,
    lastSocketError: null,
    reconnectAttempt: 0,
    isSocketStale: false,
    lastEvent: null,
  });
}

beforeEach(() => {
  seedStore();
  MockWebSocket.instances = [];
  MockWebSocket.latest = null;
  vi.stubGlobal("WebSocket", MockWebSocket);
  global.fetch = vi.fn(async (input: RequestInfo | URL) => {
    const url = String(input);
    if (url.endsWith("/api/jobs")) {
      return {
        ok: true,
        json: async () => [
          {
            id: "job-live",
            title: "Live job",
            status: "queued",
            voice_id: "suzy",
            model_id: "Qwen/Qwen3-TTS-12Hz-0.6B-Base",
            is_active_listening: false,
            total_chunks_emitted: 1,
            total_chunks_completed: 0,
            buffered_seconds: 0,
            completed_seconds: 0,
          },
        ],
      };
    }
    if (url.endsWith("/api/voices")) {
      return { ok: true, json: async () => [] };
    }
    return {
      ok: true,
      json: async () => ({
        config: useAppStore.getState().adminState?.config,
        scheduler: useAppStore.getState().adminState?.scheduler,
        telemetry: useAppStore.getState().adminState?.telemetry,
      }),
    };
  }) as typeof fetch;
});

afterEach(() => {
  vi.useRealTimers();
  cleanup();
  liveClient.resetForTests();
  vi.unstubAllGlobals();
});

test("jobs list updates from websocket events and shows live connection state", async () => {
  await act(async () => {
    render(<App />);
    await Promise.resolve();
  });

  await waitFor(() => expect(MockWebSocket.latest).not.toBeNull());
  expect(await screen.findByText(/live open/i)).toBeInTheDocument();

  expect(await screen.findByText("Live job")).toBeInTheDocument();
});

test("socket reconnects and surfaces reconnecting state", async () => {
  await act(async () => {
    render(<App />);
    await Promise.resolve();
  });

  await waitFor(() => expect(MockWebSocket.latest).not.toBeNull());

  act(() => {
    MockWebSocket.latest?.fail();
  });

  expect(await screen.findByText(/live reconnecting/i)).toBeInTheDocument();

  await waitFor(() => expect(MockWebSocket.instances).toHaveLength(2), {
    timeout: 2_500,
  });
  await waitFor(() => expect(screen.getByText(/live open/i)).toBeInTheDocument(), {
    timeout: 2_500,
  });
});

import { NavLink, Route, Routes } from "react-router-dom";
import { BrowserRouter } from "react-router-dom";

import { AdminPage } from "../features/admin/AdminPage";
import { JobsPage } from "../features/jobs/JobsPage";
import { ReaderPage } from "../features/reader/ReaderPage";
import { useAppStore } from "../state/store";

function formatSocketMessageAge(timestamp: number | null) {
  if (!timestamp) {
    return "no live events yet";
  }
  const seconds = Math.max(0, Math.round((Date.now() - timestamp) / 1000));
  return seconds === 0 ? "just now" : `${seconds}s ago`;
}

function ConnectionBadge() {
  const websocketStatus = useAppStore((state) => state.websocketStatus);
  const lastSocketMessageAt = useAppStore((state) => state.lastSocketMessageAt);
  const lastSocketError = useAppStore((state) => state.lastSocketError);
  const reconnectAttempt = useAppStore((state) => state.reconnectAttempt);
  const isSocketStale = useAppStore((state) => state.isSocketStale);

  const tone =
    websocketStatus === "open" && !isSocketStale
      ? "bg-emerald-100 text-emerald-800"
      : websocketStatus === "connecting" || websocketStatus === "reconnecting"
        ? "bg-amber-100 text-amber-900"
        : websocketStatus === "closed" && !lastSocketError
          ? "bg-stone-200 text-stone-700"
          : "bg-rose-100 text-rose-800";
  const label = websocketStatus === "closed" && !lastSocketError
    ? "idle"
    : isSocketStale
    ? "stale"
    : websocketStatus === "reconnecting"
      ? `reconnecting${reconnectAttempt ? ` #${reconnectAttempt}` : ""}`
      : websocketStatus;

  return (
    <div
      aria-live="polite"
      className={`rounded-3xl px-4 py-3 text-right text-sm ${tone}`}
      title={lastSocketError ?? "Live connection diagnostics"}
    >
      <div className="font-semibold uppercase tracking-[0.2em]">Live {label}</div>
      <div className="text-xs opacity-80">Last message: {formatSocketMessageAge(lastSocketMessageAt)}</div>
      {lastSocketError ? <div className="mt-1 max-w-64 text-xs">{lastSocketError}</div> : null}
    </div>
  );
}

function Shell() {
  return (
    <div className="app-shell px-4 py-6 md:px-8">
      <div className="mx-auto max-w-7xl">
        <header className="panel mb-6 flex flex-col gap-4 rounded-[2rem] px-6 py-5 md:flex-row md:items-center md:justify-between">
          <div>
            <div className="text-sm uppercase tracking-[0.4em] text-stone-600">ReadFlow</div>
            <div className="display-font text-3xl">Batched long-form narration</div>
          </div>
          <div className="flex flex-col gap-3 md:items-end">
            <ConnectionBadge />
            <nav className="flex gap-3">
              {[
                ["/", "Jobs"],
                ["/admin", "Admin"],
              ].map(([to, label]) => (
                <NavLink
                  className={({ isActive }) =>
                    `rounded-full px-4 py-2 text-sm font-semibold ${
                      isActive ? "bg-[var(--accent)] text-white" : "bg-white/70 text-stone-700"
                    }`
                  }
                  end={to === "/"}
                  key={to}
                  to={to}
                >
                  {label}
                </NavLink>
              ))}
            </nav>
          </div>
        </header>

        <Routes>
          <Route element={<JobsPage />} path="/" />
          <Route element={<ReaderPage />} path="/jobs/:jobId" />
          <Route element={<AdminPage />} path="/admin" />
        </Routes>
      </div>
    </div>
  );
}

export function App() {
  return (
    <BrowserRouter>
      <Shell />
    </BrowserRouter>
  );
}

import { useEffect, useMemo, useRef, useState } from "react";
