import { FormEvent, useEffect, useState } from "react";

import { api } from "../../lib/api";
import type { Voice } from "../../types/api";

interface JobCreateFormProps {
  onSubmit: (formData: FormData) => Promise<void>;
}

const MODEL_OPTIONS: { value: string; label: string }[] = [
  { value: "Qwen/Qwen3-TTS-12Hz-0.6B-Base", label: "Small (0.6B)" },
  { value: "Qwen/Qwen3-TTS-12Hz-1.7B-Base", label: "Large (1.7B)" },
];

export function JobCreateForm({ onSubmit }: JobCreateFormProps) {
  const [text, setText] = useState("");
  const [title, setTitle] = useState("");
  const [file, setFile] = useState<File | null>(null);
  const [voiceId, setVoiceId] = useState("");
  const [modelId, setModelId] = useState(MODEL_OPTIONS[0].value);
  const [voices, setVoices] = useState<Voice[]>([]);
  const [submitting, setSubmitting] = useState(false);

  useEffect(() => {
    void api.listVoices().then((nextVoices) => {
      setVoices(nextVoices);
      if (nextVoices.length > 0 && !voiceId) {
        setVoiceId(nextVoices[0].id);
      }
    });
  }, [voiceId]);

  const handleSubmit = async (event: FormEvent) => {
    event.preventDefault();
    const formData = new FormData();
    if (title) {
      formData.append("title", title);
    }
    if (text.trim()) {
      formData.append("text", text.trim());
    }
    if (file) {
      formData.append("file", file);
    }
    formData.append("voice_id", voiceId);
    formData.append("model_id", modelId);
    setSubmitting(true);
    try {
      await onSubmit(formData);
      setText("");
      setTitle("");
      setFile(null);
    } finally {
      setSubmitting(false);
    }
  };

  return (
    <form className="panel rounded-[2rem] p-6" onSubmit={handleSubmit}>
      <div className="flex flex-col gap-4">
        <div>
          <label className="mb-2 block text-sm font-semibold uppercase tracking-[0.2em] text-stone-600" htmlFor="job-title">
            Job title
          </label>
          <input
            className="w-full rounded-2xl border border-stone-300 bg-white/70 px-4 py-3"
            id="job-title"
            value={title}
            onChange={(event) => setTitle(event.target.value)}
            placeholder="Optional title"
          />
        </div>
        <div className="grid grid-cols-2 gap-4">
          <div>
            <label className="mb-2 block text-sm font-semibold uppercase tracking-[0.2em] text-stone-600" htmlFor="voice-select">
              Voice
            </label>
            <select
              className="w-full rounded-2xl border border-stone-300 bg-white/70 px-4 py-3"
              id="voice-select"
              value={voiceId}
              onChange={(event) => setVoiceId(event.target.value)}
            >
              {voices.map((voice) => (
                <option key={voice.id} value={voice.id}>
                  {voice.display_name}
                </option>
              ))}
            </select>
          </div>
          <div>
            <label className="mb-2 block text-sm font-semibold uppercase tracking-[0.2em] text-stone-600" htmlFor="model-select">
              Model
            </label>
            <select
              className="w-full rounded-2xl border border-stone-300 bg-white/70 px-4 py-3"
              id="model-select"
              value={modelId}
              onChange={(event) => setModelId(event.target.value)}
            >
              {MODEL_OPTIONS.map((option) => (
                <option key={option.value} value={option.value}>
                  {option.label}
                </option>
              ))}
            </select>
          </div>
        </div>
        <div>
          <label className="mb-2 block text-sm font-semibold uppercase tracking-[0.2em] text-stone-600" htmlFor="job-text">
            Text source
          </label>
          <textarea
            className="min-h-56 w-full rounded-3xl border border-stone-300 bg-white/70 px-4 py-3"
            id="job-text"
            value={text}
            onChange={(event) => setText(event.target.value)}
            placeholder="Paste long-form text here"
          />
        </div>
        <label className="rounded-2xl border border-dashed border-stone-400 bg-white/40 px-4 py-4 text-sm">
          <span className="font-semibold">Upload .txt instead</span>
          <input
            className="mt-2 block"
            type="file"
            accept=".txt"
            onChange={(event) => setFile(event.target.files?.[0] ?? null)}
          />
        </label>
        <button
          className="rounded-full bg-[var(--accent)] px-5 py-3 font-semibold text-white disabled:opacity-50"
          disabled={submitting || (!text.trim() && !file)}
          type="submit"
        >
          {submitting ? "Creating…" : "Create job"}
        </button>
      </div>
    </form>
  );
}

import { create } from "zustand";

import type { Voice } from "../types/api";
import type {
  AdminState,
  JobDetail,
  JobSummary,
  WsEnvelope,
} from "../types/events";

interface AppStore {
  jobs: Record<string, JobSummary>;
  voices: Voice[];
  adminState: AdminState | null;
  websocketStatus: "connecting" | "open" | "reconnecting" | "closed" | "error";
  lastSocketMessageAt: number | null;
  lastSocketError: string | null;
  reconnectAttempt: number;
  isSocketStale: boolean;
  lastEvent: WsEnvelope | null;
  setJobs: (jobs: Record<string, JobSummary>) => void;
  setVoices: (voices: Voice[]) => void;
  setAdminState: (adminState: AdminState) => void;
  setSocketState: (state: {
    status?: AppStore["websocketStatus"];
    lastMessageAt?: number | null;
    error?: string | null;
    reconnectAttempt?: number;
    isStale?: boolean;
  }) => void;
  applyEvent: (event: WsEnvelope) => void;
}

function toSummary(job: JobDetail): JobSummary {
  return {
    id: job.id,
    title: job.title,
    status: job.status,
    voice_id: job.voice_id,
    model_id: job.model_id,
    is_active_listening: job.is_active_listening,
    total_chunks_emitted: job.total_chunks_emitted,
    total_chunks_completed: job.total_chunks_completed,
    buffered_seconds: job.buffered_seconds,
    completed_seconds: job.completed_seconds,
  };
}

export const useAppStore = create<AppStore>((set) => ({
  jobs: {},
  voices: [],
  adminState: null,
  websocketStatus: "connecting",
  lastSocketMessageAt: null,
  lastSocketError: null,
  reconnectAttempt: 0,
  isSocketStale: false,
  lastEvent: null,
  setJobs: (jobs) => set({ jobs }),
  setVoices: (voices) => set({ voices }),
  setAdminState: (adminState) => set({ adminState }),
  setSocketState: ({ status, lastMessageAt, error, reconnectAttempt, isStale }) =>
    set((state) => {
      const newState = { ...state };
      let changed = false;

      if (status !== undefined && status !== state.websocketStatus) {
        newState.websocketStatus = status;
        changed = true;
      }
      if (lastMessageAt !== undefined && lastMessageAt !== state.lastSocketMessageAt) {
        newState.lastSocketMessageAt = lastMessageAt;
        changed = true;
      }
      if (error !== undefined && error !== state.lastSocketError) {
        newState.lastSocketError = error;
        changed = true;
      }
      if (reconnectAttempt !== undefined && reconnectAttempt !== state.reconnectAttempt) {
        newState.reconnectAttempt = reconnectAttempt;
        changed = true;
      }
      if (isStale !== undefined && isStale !== state.isSocketStale) {
        newState.isSocketStale = isStale;
        changed = true;
      }

      return changed ? newState : state;
    }),
  applyEvent: (event) =>
    set((state) => {
      if (
        event.type === "job_created" ||
        event.type === "job_updated" ||
        event.type === "job_completed" ||
        event.type === "chunk_ready"
      ) {
        return {
          jobs: { ...state.jobs, [event.payload.job.id]: toSummary(event.payload.job) },
          lastEvent: event,
        };
      }

      if (event.type === "telemetry" && state.adminState) {
        return {
          adminState: {
            ...state.adminState,
            telemetry: event.payload.telemetry,
          },
          lastEvent: event,
        };
      }

      if (event.type === "admin_config_updated" && state.adminState) {
        return {
          adminState: {
            ...state.adminState,
            config: event.payload,
          },
          lastEvent: event,
        };
      }

      if (event.type === "scheduler_state" && state.adminState) {
        return {
          adminState: {
            ...state.adminState,
            scheduler: event.payload,
          },
          lastEvent: event,
        };
      }

      if (event.type === "model_state" && state.adminState) {
        const telemetry = state.adminState.telemetry;
        return {
          adminState: {
            ...state.adminState,
            telemetry: telemetry
              ? { ...telemetry, model_state: event.payload.state }
              : null,
          },
          lastEvent: event,
        };
      }

      return state;
    }),
}));

